// src/pages/Attendance/AttendanceInboxPage.js
import React, { useState, useEffect, useCallback } from 'react';
import { attendanceAPI } from '../../api/services';
import { Badge, SkeletonTable, InlineSpinner } from '../../components/common';
import { Check, X } from 'lucide-react';
import toast from 'react-hot-toast';

function ActionButtons({ onApprove, onReject, loading }) {
  return (
    <div style={{ display: 'flex', gap: 6 }}>
      <button className="btn btn-success btn-sm" onClick={onApprove} disabled={!!loading}>
        {loading === 'approve' ? <InlineSpinner /> : <><Check size={13} /> Approve</>}
      </button>
      <button className="btn btn-danger btn-sm" onClick={onReject} disabled={!!loading}>
        {loading === 'reject' ? <InlineSpinner /> : <><X size={13} /> Reject</>}
      </button>
    </div>
  );
}

export default function AttendanceInboxPage() {
  const [tab,         setTab]         = useState('corrections');
  const [corrections, setCorrections] = useState([]);
  const [overtime,    setOvertime]    = useState([]);
  const [loading,     setLoading]     = useState(true);
  const [acting,      setActing]      = useState({});

  const unwrap = r => { const o = r?.data; return o && 'data' in o ? o.data : o; };
  const toArr  = (r, keys) => { const p = unwrap(r); if (Array.isArray(p)) return p; for (const k of keys) if (Array.isArray(p?.[k])) return p[k]; return []; };

  const load = useCallback(() => {
    setLoading(true);
    Promise.all([
      attendanceAPI.listCorrections({ status: 'Pending' }),
      attendanceAPI.listShifts(), // reuse to get overtime via separate call
    ]).then(([c]) => {
      setCorrections(toArr(c, ['corrections','data']));
      setLoading(false);
    }).catch(() => setLoading(false));
  }, []);

  useEffect(() => { load(); }, [load]);

  const actOnCorrection = async (id, action) => {
    setActing(a => ({ ...a, [id]: action }));
    try {
      await attendanceAPI.reviewCorrection(id, { action, reviewNote: '' });
      toast.success(`Correction ${action}d`);
      load();
    } catch (err) {
      toast.error(err.response?.data?.error?.message || 'Action failed');
    } finally { setActing(a => ({ ...a, [id]: null })); }
  };

  const actOnOvertime = async (id, action) => {
    setActing(a => ({ ...a, [`ot_${id}`]: action }));
    try {
      await attendanceAPI.approveOvertime(id, { action });
      toast.success(`Overtime request ${action}d`);
      load();
    } catch (err) {
      toast.error(err.response?.data?.error?.message || 'Action failed');
    } finally { setActing(a => ({ ...a, [`ot_${id}`]: null })); }
  };

  const pendingCount = corrections.filter(c => (c.Status || c.status) === 'Pending').length;

  return (
    <>
      <div className="page-header">
        <h1>Manager Inbox</h1>
        <p>Review and action pending attendance requests</p>
      </div>

      <div className="tabs">
        <button className={`tab-btn ${tab === 'corrections' ? 'active' : ''}`} onClick={() => setTab('corrections')}>
          Correction Requests {pendingCount > 0 && <span className="nav-badge" style={{ marginLeft: 6 }}>{pendingCount}</span>}
        </button>
        <button className={`tab-btn ${tab === 'overtime' ? 'active' : ''}`} onClick={() => setTab('overtime')}>
          Overtime Requests
        </button>
      </div>

      {loading ? <SkeletonTable rows={5} /> : (

        tab === 'corrections' ? (
          corrections.length === 0 ? (
            <div className="card">
              <div style={{ textAlign: 'center', padding: 50, color: 'var(--text-muted)' }}>
                <div style={{ fontSize: '2rem', marginBottom: 8 }}>✅</div>
                No pending correction requests
              </div>
            </div>
          ) : (
            <div className="table-wrap">
              <table>
                <thead>
                  <tr><th>Employee</th><th>Date</th><th>Requested Check-In</th><th>Requested Check-Out</th><th>Reason</th><th>Status</th><th>Action</th></tr>
                </thead>
                <tbody>
                  {corrections.map((c, i) => {
                    const id     = c.CorrectionID || c.correctionID || c.id;
                    const status = c.Status || c.status || 'Pending';
                    return (
                      <tr key={id || i}>
                        <td style={{ fontWeight: 500 }}>{c.EmployeeName || c.employeeName || c.Employee?.FullName || '—'}</td>
                        <td>{c.AttendanceDate || c.attendanceDate ? new Date(c.AttendanceDate || c.attendanceDate).toLocaleDateString() : '—'}</td>
                        <td>{c.CorrectedCheckIn  || c.correctedCheckIn  || '—'}</td>
                        <td>{c.CorrectedCheckOut || c.correctedCheckOut || '—'}</td>
                        <td style={{ maxWidth: 200 }}><span className="truncate" style={{ display: 'block' }}>{c.Reason || c.reason || '—'}</span></td>
                        <td><Badge status={status}>{status}</Badge></td>
                        <td>
                          {status === 'Pending' && (
                            <ActionButtons
                              loading={acting[id]}
                              onApprove={() => actOnCorrection(id, 'approve')}
                              onReject={()  => actOnCorrection(id, 'reject')}
                            />
                          )}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )
        ) : (
          <div className="card">
            <div style={{ textAlign: 'center', padding: 50, color: 'var(--text-muted)' }}>
              Overtime requests will appear here
            </div>
          </div>
        )
      )}
    </>
  );
}
